def is_valid_sudoku(board):
    rows, cols, boxes = [set() for _ in range(9)], [set() for _ in range(9)], [set() for _ in range(9)]
    for i in range(9):
        for j in range(9):
            num = board[i][j]
            if num == '.':
                continue
            if num in rows[i] or num in cols[j] or num in boxes[(i // 3) * 3 + (j // 3)]:
                return False
            rows[i].add(num)
            cols[j].add(num)
            boxes[(i // 3) * 3 + (j // 3)].add(num)
    return True

