def combination_sum(candidates, target):
    result = []
    def backtrack(path, start, target):
        if target == 0:
            result.append(path[:])
            return
        if target < 0:
            return
        for i in range(start, len(candidates)):
            path.append(candidates[i])
            backtrack(path, i, target - candidates[i])
            path.pop()
    backtrack([], 0, target)
    return result

