#include <vector>
#include <queue>
int numIslands(std::vector<std::vector<char>>& grid) {
    if (grid.empty()) return 0;
    int numRows = grid.size(), numCols = grid[0].size();
    int count = 0;
    std::vector<std::vector<bool>> visited(numRows, std::vector<bool>(numCols, false));
    auto bfs = [&](int r, int c) {
        std::queue<std::pair<int, int>> q;
        q.push({r, c});
        visited[r][c] = true;
        while (!q.empty()) {
            auto [cur_r, cur_c] = q.front();
            q.pop();
            for (auto [dr, dc] : std::vector<std::pair<int, int>>{{1, 0}, {-1, 0}, {0, 1}, {0, -1}}) {
                int nr = cur_r + dr, nc = cur_c + dc;
                if (nr >= 0 && nr < numRows && nc >= 0 && nc < numCols && grid[nr][nc] == '1' && !visited[nr][nc]) {
                    q.push({nr, nc});
                    visited[nr][nc] = true;
                }
            }
        }
    };
    for (int r = 0; r < numRows; ++r) {
        for (int c = 0; c < numCols; ++c) {
            if (grid[r][c] == '1' && !visited[r][c]) {
                bfs(r, c);
                count++;
            }
        }
    }
    return count;
}

