std::string minWindow(std::string s, std::string t) {
    std::unordered_map<char, int> countT;
    for (char c : t) countT[c]++;
    int required = countT.size();
    std::unordered_map<char, int> windowCounts;
    int l = 0, r = 0, formed = 0;
    int min_len = INT_MAX, min_l = 0;
    std::string min_window;

    while (r < s.size()) {
        windowCounts[s[r]]++;
        if (countT.find(s[r]) != countT.end() && windowCounts[s[r]] == countT[s[r]]) formed++;

        while (l <= r && formed == required) {
            if (r - l + 1 < min_len) {
                min_len = r - l + 1;
                min_l = l;
                min_window = s.substr(l, min_len);
            }
            windowCounts[s[l]]--;
            if (countT.find(s[l]) != countT.end() && windowCounts[s[l]] < countT[s[l]]) formed--;
            l++;
        }
        r++;
    }
    return min_window;
}

