std::string longestPalindrome(const std::string& s) {
    auto expandAroundCenter = [&](int left, int right) {
        while (left >= 0 && right < s.size() && s[left] == s[right]) {
            --left;
            ++right;
        }
        return s.substr(left + 1, right - left - 1);
    };
    std::string longest;
    for (int i = 0; i < s.size(); ++i) {
        std::string pal1 = expandAroundCenter(i, i);
        std::string pal2 = expandAroundCenter(i, i + 1);
        std::string maxPal = pal1.size() > pal2.size() ? pal1 : pal2;
        if (maxPal.size() > longest.size()) {
            longest = maxPal;
        }
    }
    return longest;
}

