#include <vector>
#include <stack>
int largestRectangleArea(std::vector<int>& heights) {
    std::stack<int> stack;
    int maxArea = 0, index = 0;
    heights.push_back(0);
    while (index < heights.size()) {
        if (stack.empty() || heights[index] >= heights[stack.top()])
            stack.push(index++);
        else {
            int height = heights[stack.top()];
            stack.pop();
            int width = stack.empty() ? index : index - stack.top() - 1;
            maxArea = std::max(maxArea, height * width);
        }
    }
    return maxArea;
}
int maximalRectangle(std::vector<std::vector<char>>& matrix) {
    if (matrix.empty() || matrix[0].empty()) return 0;
    int m = matrix.size(), n = matrix[0].size(), maxArea = 0;
    std::vector<int> heights(n, 0);
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            heights[j] = matrix[i][j] == '1' ? heights[j] + 1 : 0;
        }
        maxArea = std::max(maxArea, largestRectangleArea(heights));
    }
    return maxArea;
}

