bool hasCycle(int node, const unordered_map<int, vector<int>>& graph, unordered_set<int>& visited, unordered_set<int>& path) {
    if (path.count(node)) return true;
    if (visited.count(node)) return false;
    visited.insert(node);
    path.insert(node);
    for (int neighbor : graph.at(node)) {
        if (hasCycle(neighbor, graph, visited, path)) return true;
    }
    path.erase(node);
    return false;
}
