    for (const auto& edge : prerequisites) {
        graph[edge[1]].push_back(edge[0]);
    }
    unordered_set<int> visited, path;
    for (int i = 0; i < numCourses; ++i) {
        if (hasCycle(i, graph, visited, path)) return false;
    }
    return true;
}

