def solve_n_queens(n: int):
    def is_valid(board, row, col):
        for i in range(row):
            if board[i] == col or 
               board[i] - i == col - row or 
               board[i] + i == col + row:
                return False
        return True

    def solve(row):
        if row == n:
            result.append([''.join(row) for row in board])
            return
        for col in range(n):
            if is_valid(board, row, col):
                board[row] = col
                solve(row + 1)
                board[row] = '.'

    result = []
    board = ['.' * n for _ in range(n)]
    solve(0)
    return result

