def solve_sudoku(board):
    def is_valid(r, c, num):
        for i in range(9):
            if board[r][i] == num or board[i][c] == num or board[3 * (r // 3) + i // 3][3 * (c // 3) + i % 3] == num:
                return False
        return True
    def solve():
        for r in range(9):
            for c in range(9):
                if board[r][c] == 0:
                    for num in range(1, 10):
                        if is_valid(r, c, num):
                            board[r][c] = num
                            if solve():
                                return True
                            board[r][c] = 0
                    return False
        return True
    solve()

