int totalNQueens(int n) {
    int count = 0;
    function<void(int, int, int, int)> backtrack = [&](int row, int cols, int diag1, int diag2) {
        if (row == n) {
            count++;
            return;
        }
        for (int col = 0; col < n; ++col) {
            if ((cols & (1 << col)) == 0 && (diag1 & (1 << (row - col + n - 1))) == 0 && (diag2 & (1 << (row + col))) == 0) {
                backtrack(row + 1, cols | (1 << col), diag1 | (1 << (row - col + n - 1)), diag2 | (1 << (row + col)));
            }
        }
    };
    backtrack(0, 0, 0, 0);
    return count;
}

