from collections import deque

def shortest_path(grid, k):
    m, n = len(grid), len(grid[0])
    queue = deque([(0, 0, 0, 0)])
    visited = {(0, 0): 0}
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    while queue:
        x, y, steps, obstacles = queue.popleft()
        if x == m - 1 and y == n - 1:
            return steps
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < m and 0 <= ny < n:
                new_obstacles = obstacles + grid[nx][ny]
                if new_obstacles <= k and (nx, ny) not in visited or new_obstacles < visited[(nx, ny)]:
                    visited[(nx, ny)] = new_obstacles
                    queue.append((nx, ny, steps + 1, new_obstacles))
    return -1

