def find_all_concatenated_words_in_a_dict(words):
    word_set = set(words)
    memo = {}

    def can_form(word):
        if word in memo:
            return memo[word]
        for i in range(1, len(word)):
            prefix = word[:i]
            suffix = word[i:]
            if prefix in word_set and (suffix in word_set or can_form(suffix)):
                memo[word] = True
                return True
        memo[word] = False
        return False

    result = []
    for word in words:
        if can_form(word):
            result.append(word)
    return result

