from bisect import bisect_left

def max_envelopes(envelopes):
    if not envelopes:
        return 0
    envelopes.sort(key=lambda x: (x[0], -x[1]))
    dp = []
    for _, height in envelopes:
        idx = bisect_left(dp, height)
        if idx == len(dp):
            dp.append(height)
        else:
            dp[idx] = height
    return len(dp)

