def kth_smallest(matrix, k):
    n = len(matrix)
    left, right = matrix[0][0], matrix[n-1][n-1]
    while left < right:
        mid = (left + right) // 2
        count = sum([self.helper(row, mid) for row in matrix])
        if count < k:
            left = mid + 1
        else:
            right = mid
    return left

    def helper(self, row, x):
        l, r = 0, len(row)
        while l < r:
            m = (l + r) // 2
            if row[m] <= x:
                l = m + 1
            else:
                r = m
        return l

