def countVowelPermutation(n):
    MOD = 10**9 + 7
    a, e, i, o, u = 1, 1, 1, 1, 1
    for _ in range(2, n + 1):
        a, e, i, o, u = (e + i + u) % MOD, (a + i) % MOD, (e + o) % MOD, i % MOD, (i + o) % MOD
    return (a + e + i + o + u) % MOD

