def findMaxValueOfEquation(points, k):
    result = float('-inf')
    deq = deque()

    for x, y in points:
        while deq and x - deq[0][0] > k:
            deq.popleft()

        if deq:
            result = max(result, y + x + deq[0][1] - deq[0][0])

        while deq and deq[-1][1] - deq[-1][0] < y - x:
            deq.pop()

        deq.append((x, y))

