        if row == n:
            result.append([''.join(row) for row in board])
            return
        for col in range(n):
            if isValid(row, col):
                board[row][col] = 'Q'
                solve(row + 1)
                board[row][col] = '.'

    def isValid(row, col):
        for i in range(row):
            if board[i][col] == 'Q':
                return False
        for i, j in zip(range(row, -1, -1), range(col, -1, -1)):
            if board[i][j] == 'Q':
                return False
        for i, j in zip(range(row, -1, -1), range(col, n)):
            if board[i][j] == 'Q':
                return False
        return True

    result = []
    board = [['.' for _ in range(n)] for _ in range(n)]
    solve(0)
    return result

