from collections import deque, defaultdict

def findLadders(beginWord, endWord, wordList):
    wordSet = set(wordList)
    if endWord not in wordSet:
        return []
    results = []
    queue = deque([[beginWord]])
    visited = set([beginWord])
    minDepth = {beginWord: 1}

    while queue:
        found = False
        levelVisited = set()
        for _ in range(len(queue)):
            path = queue.popleft()
            word = path[-1]
            for neighbor in getNeighbors(word):
                if neighbor == endWord:
                    results.append(path + [neighbor])
                    found = True
                elif neighbor not in visited:
                    levelVisited.add(neighbor)
                    queue.append(path + [neighbor])
                    minDepth[neighbor] = minDepth.get(word, 0) + 1
        visited.update(levelVisited)
        if found:
            break

    return results

    def getNeighbors(word):
        neighbors = []
        for i in range(len(word)):
            for c in range(26):
                nextWord = word[:i] + chr(c + 97) + word[i + 1:]
                if nextWord in wordSet and nextWord != word:
                    neighbors.append(nextWord)
        return neighbors

