class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def reverseKGroup(head, k):
    dummy = ListNode(0)
    dummy.next = head
    prevGroupEnd = dummy
    while head:
        end = head
        for i in range(1, k):
            if not end:
                return dummy.next
            end = end.next
        if not end:
            return dummy.next
        nextGroupStart = end.next
        prev, curr = nextGroupStart, head
        while curr != nextGroupStart:
            curr.next, prev, curr = prev, curr, curr.next
        prevGroupEnd.next, prevGroupEnd = end, head
        head = nextGroupStart
    return dummy.next

