def countInversions(arr):
    def mergeSort(arr, tempArr, left, right):
        invCount = 0
        if left < right:
            mid = (left + right) // 2
            invCount += mergeSort(arr, tempArr, left, mid)
            invCount += mergeSort(arr, tempArr, mid + 1, right)
            invCount += merge(arr, tempArr, left, mid, right)
        return invCount

    def merge(arr, tempArr, left, mid, right):
        i, j, k = left, mid + 1, left
        invCount = 0
        while i <= mid and j <= right:
            if arr[i] <= arr[j]:
                tempArr[k] = arr[i]
                i += 1
            else:
                tempArr[k] = arr[j]
                invCount += (mid - i + 1)
                j += 1
            k += 1
        while i <= mid:
            tempArr[k] = arr[i]
            i += 1
            k += 1
        while j <= right:
            tempArr[k] = arr[j]
            j += 1
            k += 1
        for i in range(left, right + 1):
            arr[i] = tempArr[i]
        return invCount

    tempArr = [0] * len(arr)
    return mergeSort(arr, tempArr, 0, len(arr) - 1)

