def uniquePathsIII(grid):
    m, n = len(grid), len(grid[0])
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    start = end = empty_count = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] == 1:
                start = (i, j)
            if grid[i][j] == 2:
                end = (i, j)
            if grid[i][j] == 0:
                empty_count += 1

    def dfs(x, y, count):
        if x < 0 or x >= m or y < 0 or y >= n or grid[x][y] == -1:
            return 0
        if (x, y) == end:
            return 1 if count == empty_count else 0
        grid[x][y] = -1
        total_paths = 0
        for dx, dy in directions:
            total_paths += dfs(x + dx, y + dy, count + 1)
        grid[x][y] = 0
        return total_paths

    return dfs(*start, 0)

