def findAnagrams(s, p):
    from collections import Counter
    result = []
    p_count = Counter(p)
    s_count = Counter(s[:len(p)])
    if p_count == s_count:
        result.append(0)
    for i in range(len(p), len(s)):
        s_count[s[i]] += 1
        s_count[s[i - len(p)]] -= 1
        if s_count[s[i - len(p)]] == 0:
            del s_count[s[i - len(p)]]
        if p_count == s_count:
            result.append(i - len(p) + 1)
    return result

solution.c++:
#include <vector>
#include <string>
#include <unordered_map>
using namespace std;

vector<int> findAnagrams(string s, string p) {
    vector<int> result;
    unordered_map<char, int> pCount, sCount;
    for (char c : p) pCount[c]++;
    for (int i = 0; i < p.size(); ++i) sCount[s[i]]++;
    if (pCount == sCount) result.push_back(0);
    for (int i = p.size(); i < s.size(); ++i) {
        sCount[s[i]]++;
        sCount[s[i - p.size()]]--;
        if (sCount[s[i - p.size()]] == 0) sCount.erase(s[i - p.size()]);
        if (pCount == sCount) result.push_back(i - p.size() + 1);
    }
    return result;
}

