#include <algorithm>
using namespace std;

class Solution { public: int numIslands(vector<vector<char>>& grid) { if (grid.empty()) return 0; int rows = grid.size(); int cols = grid[0].size(); int count = 0; for (int r = 0; r < rows; ++r) { for (int c = 0; c < cols; ++c) { if (grid[r][c] == '1') { count++; dfs(grid, r, c); } } } return count; } private: void dfs(vector<vector<char>>& grid, int r, int c) { if (r < 0 || r >= grid.size() || c < 0 || c >= grid[0].size() || grid[r][c] == '0') return; grid[r][c] = '0'; dfs(grid, r - 1, c); dfs(grid, r + 1, c); dfs(grid, r, c - 1); dfs(grid, r, c + 1); } };

