def ladderLength(beginWord, endWord, wordList):
    word_set = set(wordList)
    if endWord not in word_set:
        return 0
    queue = [(beginWord, 1)]
    while queue:
        word, length = queue.pop(0)
        if word == endWord:
            return length
        for i in range(len(word)):
            for char in 'abcdefghijklmnopqrstuvwxyz':
                new_word = word[:i] + char + word[i+1:]
                if new_word in word_set:
                    word_set.remove(new_word)
                    queue.append((new_word, length + 1))
    return 0

solution.c++:
#include <unordered_set>
#include <queue>
#include <string>
#include <utility>
using namespace std;

class Solution { public: int ladderLength(string beginWord, string endWord, vector<string>& wordList) { unordered_set<string> wordSet(wordList.begin(), wordList.end()); if (wordSet.find(endWord) == wordSet.end()) return 0; queue<pair<string, int>> q; q.push({beginWord, 1}); while (!q.empty()) { auto [word, length] = q.front(); q.pop(); if (word == endWord) return length; for (int i = 0; i < word.length(); i++) { string chars = word; for (char c = 'a'; c <= 'z'; c++) { chars[i] = c; if (wordSet.find(chars) != wordSet.end()) { wordSet.erase(chars); q.push({chars, length + 1}); } } } } return 0; } };

