#include <algorithm>
#include <cctype>
#include <string>
bool isPalindrome(const std::string& s) { std::string cleaned;
    for (char c : s) {
        if (std::isalnum(c)) cleaned += std::tolower(c);
    }
    std::string reversed = cleaned;
    std::reverse(reversed.begin(), reversed.end());
    return cleaned == reversed;
}

